//! ~80 lines of code, rarely needs editing.

use anyhow::{Context, Result};
use crossterm::event::{Event, KeyCode, KeyEventKind};
use crossterm::{event, terminal};
use libloading::{Library, Symbol};
use protocol::{App, AppState};
use ratatui::{backend::CrosstermBackend, Terminal};
use std::path::PathBuf;
use std::time::Duration;
use tracing::{error, info};

/// Load the app dylib.
fn load_dylib(path: &Path) -> Result<Box<dyn App>> {
    unsafe {
        let lib = Library::new(path).context("Failed to load dylib")?;
        let create_app: Symbol<unsafe extern "C" fn() -> *mut dyn App> =
            lib.get(b"create_app").context("Failed to find create_app")?;
        let app = create_app();
        Ok(Box::from_raw(app))
    }
}

/// Get the current dylib path.
fn current_dylib() -> PathBuf {
    PathBuf::from("target/hot/.current")
}

/// Check for protocol changes (restart needed).
fn check_protocol_change() -> bool {
    PathBuf::from("target/hot/.restart-needed").exists()
}

fn main() -> Result<()> {
    // Initialize terminal
    terminal::enable_raw_mode()?;
    let mut stdout = std::io::stdout();
    crossterm::execute!(stdout, terminal::EnterAlternateScreen)?;

    let backend = CrosstermBackend::new(stdout);
    let mut terminal = Terminal::new(backend)?;

    // Load initial dylib
    let dylib_path = current_dylib();
    info!("Loading dylib: {:?}", dylib_path);

    let mut app = if dylib_path.exists() {
        load_dylib(&dylib_path)?
    } else {
        error!("No dylib found at {:?}", dylib_path);
        return Ok(());
    };

    // Main event loop
    let mut state = AppState::default();
    let tick_rate = Duration::from_millis(100);

    loop {
        // Render
        terminal.draw(|f| {
            let widget = app.render(&state);
            f.render_widget(widget, f.size());
        })?;

        // Handle events
        if event::poll(tick_rate)? {
            if let Event::Key(key) = event::read()? {
                if key.kind == KeyEventKind::Press {
                    match key.code {
                        KeyCode::Char('q') | KeyCode::Esc => {
                            state.should_exit = true;
                        }
                        _ => {}
                    }
                    app.handle_key(key, &mut state);
                }
            }
        }

        // Update
        app.update(&mut state);

        // Check for exit
        if state.should_exit {
            break;
        }

        // Check for dylib reload
        if let Ok(new_path) = std::fs::read_link(&dylib_path) {
            // Reload if changed
            if new_path != dylib_path {
                info!("Reloading dylib: {:?}", new_path);
                app = load_dylib(&new_path)?;
            }
        }
    }

    // Cleanup
    terminal::disable_raw_mode()?;
    let _ = crossterm::execute!(terminal.backend_mut(), terminal::LeaveAlternateScreen);

    Ok(())
}

// main.r.ts - Main entry point for the app logic

import { AppState, Task, Filter } from "./state.r.ts";

/**
 * Update application state.
 * Called by the host on each tick.
 */
export function update(state: AppState): void {
    // Filter tasks based on current filter
    const filtered = filterTasks(state.tasks, state.filter);

    // Clamp selected index
    if (state.selected >= filtered.length && filtered.length > 0) {
        state.selected = filtered.length - 1;
    }
}

/**
 * Filter tasks by completion status.
 */
export function filterTasks(tasks: Task[], filter: Filter): Task[] {
    switch (filter) {
        case Filter.Active:
            return tasks.filter(t => !t.done);
        case Filter.Completed:
            return tasks.filter(t => t.done);
        default:
            return tasks;
    }
}

/**
 * Get statistics about tasks.
 */
export function getStats(tasks: Task[]): { total: number; done: number; active: number } {
    const done = tasks.filter(t => t.done).length;
    return {
        total: tasks.length,
        done,
        active: tasks.length - done,
    };
}

/**
 * Find task by ID.
 */
export function findTask(tasks: Task[], id: number): Task | null {
    for (const task of tasks) {
        if (task.id === id) {
            return task;
        }
    }
    return null;
}

/**
 * Sort tasks by various criteria.
 */
export function sortTasks(tasks: Task[], by: "id" | "title" | "done"): Task[] {
    const sorted = [...tasks];
    switch (by) {
        case "id":
            return sorted.sort((a, b) => a.id - b.id);
        case "title":
            return sorted.sort((a, b) => a.title.localeCompare(b.title));
        case "done":
            return sorted.sort((a, b) => (a.done === b.done) ? 0 : a.done ? 1 : -1);
        default:
            return sorted;
    }
}

// state.r.ts - Application state types

/**
 * A task item.
 */
export type Task = {
    id: number;
    title: string;
    done: boolean;
};

/**
 * Filter mode for task list.
 */
export enum Filter {
    All = "all",
    Active = "active",
    Completed = "completed",
}

/**
 * Application state owned by host.
 */
export type AppState = {
    tasks: Task[];
    selected: number;
    filter: Filter;
    shouldExit: boolean;
};

/**
 * Message types for the app.
 */
export type Message =
    | { tag: "AddTask", title: string }
    | { tag: "ToggleTask", id: number }
    | { tag: "DeleteTask", id: number }
    | { tag: "SelectTask", index: number }
    | { tag: "SetFilter", filter: Filter }
    | { tag: "Quit" };

/**
 * Result type for operations.
 */
export type Result<T, E = string> =
    | { ok: true, value: T }
    | { ok: false, error: E };

/**
 * Create a new task.
 */
export function createTask(title: string): Task {
    return {
        id: Date.now(),
        title,
        done: false,
    };
}

/**
 * Toggle task completion.
 */
export function toggleTask(task: Task): Task {
    return { ...task, done: !task.done };
}

/**
 * Validate task title.
 */
export function validateTitle(title: string): Result<string> {
    const trimmed = title.trim();
    if (trimmed.length === 0) {
        return { ok: false, error: "Title cannot be empty" };
    }
    if (trimmed.length > 100) {
        return { ok: false, error: "Title too long (max 100 chars)" };
    }
    return { ok: true, value: trimmed };
}

// root.r.tsx - Root view component

import { AppState, Task } from "../state.r.ts";
import { Block, List, ListItem, Paragraph, Sparkline, BorderType, Direction } from "rune/ui";

/**
 * Root view props.
 */
interface RootViewProps {
    tasks: Task[];
    selected: number;
    filter: string;
}

/**
 * Main root view component.
 * Transpiles to Ratatui widget construction.
 */
export function RootView(props: RootViewProps): Widget {
    return (
        <Block title="TODOX" borders={BorderType.Single}>
            <List selected={props.selected}>
                {props.tasks.map((task, i) => (
                    <ListItem
                        key={task.id}
                        selected={i === props.selected}
                    >
                        <Checkbox checked={task.done} />
                        {task.title}
                    </ListItem>
                ))}
            </List>
            <Footer tasks={props.tasks} />
        </Block>
    );
}

/**
 * Checkbox component.
 */
function Checkbox(props: { checked: boolean }): string {
    return props.checked ? "[x]" : "[ ]";
}

/**
 * Footer with task statistics.
 */
function Footer(props: { tasks: Task[] }): Paragraph {
    const done = props.tasks.filter(t => t.done).length;
    const total = props.tasks.length;
    return (
        <Paragraph>
            {done}/{total} completed
        </Paragraph>
    );
}

/**
 * Progress bar using sparkline.
 */
function ProgressBar(props: { tasks: Task[] }): Widget {
    const values = props.tasks.map(t => (t.done ? 1.0 : 0.0));
    return (
        <Sparkline
            data={values}
            direction={Direction.Horizontal}
        />
    );
}

/**
 * Task list item with actions.
 */
function TaskItem(props: { task: Task; selected: boolean }): ListItem {
    return (
        <ListItem
            selected={props.selected}
            style={props.task.done ? "strikethrough" : "normal"}
        >
            {props.task.done ? "[x] " : "[ ] "}
            {props.task.title}
        </ListItem>
    );
}

//! # Build Driver
//!
//! Main compilation orchestration.

use std::path::PathBuf;
use std::process::Command as ProcCommand;
use crate::{Result, parser, analyzer, codegen};
use super::config::RuneConfig;
use super::cache::CacheManager;

/// Build mode.
#[derive(Debug, Clone, Copy, Default)]
pub enum BuildMode {
    /// Development with hot reload
    #[default]
    Dev,
    /// Release build
    Release,
}

/// Options for building.
#[derive(Debug, Clone)]
pub struct BuildOptions {
    /// Mode to build in
    pub mode: BuildMode,
    /// Working directory
    pub workspace: PathBuf,
    /// Target crate name
    pub target_crate: Option<String>,
    /// Config file path
    pub config: Option<PathBuf>,
    /// File to transpile (for transpile command)
    pub transpile_file: Option<PathBuf>,
    /// Verbose output
    pub verbose: bool,
}

impl BuildOptions {
    /// Create new options.
    #[must_use]
    pub const fn new(workspace: PathBuf) -> Self {
        Self {
            mode: BuildMode::Dev,
            workspace,
            target_crate: None,
            config: None,
            transpile_file: None,
            verbose: false,
        }
    }

    /// Set development mode.
    #[must_use]
    pub const fn dev(mut self) -> Self {
        self.mode = BuildMode::Dev;
        self
    }

    /// Set release mode.
    #[must_use]
    pub const fn release(mut self) -> Self {
        self.mode = BuildMode::Release;
        self
    }
}

/// Main build driver.
pub struct BuildDriver {
    options: BuildOptions,
    config: RuneConfig,
    cache: CacheManager,
}

impl BuildDriver {
    /// Create a new build driver.
    ///
    /// # Errors
    /// Returns an error if configuration or cache cannot be initialized.
    pub fn new(options: BuildOptions) -> Result<Self> {
        let config_path = options.config.clone()
            .or_else(|| Some(options.workspace.join("rune.toml")));

        let config = if let Some(ref path) = config_path {
            if path.exists() {
                RuneConfig::load(path)?
            } else {
                RuneConfig::default()
            }
        } else {
            RuneConfig::default()
        };

        let cache = CacheManager::new(&options.workspace)?;

        Ok(Self {
            options,
            config,
            cache,
        })
    }

    /// Run in development mode with hot reload.
    ///
    /// # Errors
    /// Returns an error if build fails.
    pub fn dev(&mut self) -> Result<()> {
        if self.options.verbose {
            println!("Running in development mode with hot reload...");
        }

        let sources = self.find_sources()?;
        if self.options.verbose {
            println!("Found {} Rune source files", sources.len());
        }

        let parsed = Self::parse_sources(&sources)?;
        let analyses = Self::analyze_sources(&parsed)?;
        let generated = self.generate_code(&parsed, &analyses)?;
        self.write_generated(&generated)?;
        self.build_crate(false)?;
        self.setup_hot_reload()?;

        if self.options.verbose {
            println!("Development build complete. Dylib ready.");
        }

        Ok(())
    }

    /// Run in release mode.
    ///
    /// # Errors
    /// Returns an error if build fails.
    pub fn build(&mut self) -> Result<()> {
        if self.options.verbose {
            println!("Running in release mode...");
        }

        let sources = self.find_sources()?;
        let parsed = Self::parse_sources(&sources)?;
        let analyses = Self::analyze_sources(&parsed)?;
        let generated = self.generate_code(&parsed, &analyses)?;
        self.write_generated(&generated)?;
        self.build_crate(true)?;

        if self.options.verbose {
            println!("Release build complete.");
        }

        Ok(())
    }

    /// Type check only.
    ///
    /// # Errors
    /// Returns an error if analysis fails.
    pub fn check(&mut self) -> Result<()> {
        let sources = self.find_sources()?;
        let parsed = Self::parse_sources(&sources)?;
        let analyses = Self::analyze_sources(&parsed)?;

        for analysis in &analyses {
            for warning in &analysis.warnings {
                println!("warning: {} at {}", warning.message, warning.location);
            }
        }

        println!("Type check passed for {} files.", parsed.len());
        Ok(())
    }

    /// Transpile a single file to stdout.
    ///
    /// # Errors
    /// Returns an error if transpilation fails.
    pub fn transpile(&mut self) -> Result<()> {
        let file = self.options.transpile_file.as_ref()
            .ok_or_else(|| crate::RuneError::Codegen("No file specified".into()))?;

        let source = parser::parse_file(file)?;
        let analysis = analyzer::analyze(&source)?;
        let module = codegen::generate(&source, &analysis)?;

        println!("{}", module.source);
        Ok(())
    }

    /// Initialize a new project.
    ///
    /// # Errors
    /// Returns an error if project creation fails.
    #[allow(clippy::too_many_lines)]
    pub fn init(&mut self) -> Result<()> {
        let project_name = self.config.project.name.clone();
        let target_crate = self.config.build.target_crate.clone();

        let base = self.options.workspace.join("crates").join(&target_crate);
        std::fs::create_dir_all(base.join("src/native"))?;
        std::fs::create_dir_all(base.join("src/views"))?;

        let cargo = format!(r#"[package]
name = "{target_crate}"
version = "0.1.0"
edition = "2021"

[lib]
name = "{target_crate}"
path = "src/lib.rs"

[dependencies]
protocol = {{ path = "../protocol" }}
ratatui = "0.26"

[build-dependencies]
rune = {{ path = "../../.." }}
"#);

        std::fs::write(base.join("Cargo.toml"), cargo)?;

        let lib = r#"mod native;

pub struct AppState {
    pub tasks: Vec<Task>,
}

#[derive(Clone)]
pub struct Task {
    pub id: i32,
    pub title: String,
    pub done: bool,
}

#[no_mangle]
pub extern "C" fn create_app() -> *mut dyn protocol::App {
    Box::into_raw(Box::new(AppImpl))
}

struct AppImpl;

impl protocol::App for AppImpl {
    fn update(&mut self, _state: &mut AppState) {}
    fn render(&self, _term: &mut impl ratatui::backend::Backend, _state: &AppState) {}
}
"#;

        std::fs::write(base.join("src/lib.rs"), lib)?;

        let main_ts = "export function update(state: AppState): void {}\n\
export function render(state: AppState): void {}\n";

        std::fs::write(base.join("src/main.r.ts"), main_ts)?;

        let state_ts = "export type Task = { id: number; title: string; done: boolean };\n\
export type AppState = { tasks: Task[]; selected: number };\n";

        std::fs::write(base.join("src/state.r.ts"), state_ts)?;

        let native_mod = "pub mod fast_math;\n";
        std::fs::write(base.join("src/native/mod.rs"), native_mod)?;

        let fast_math = "pub fn fast_sqrt(x: f64) -> f64 { x.sqrt() }\n";
        std::fs::write(base.join("src/native/fast_math.rs"), fast_math)?;

        println!("Initialized Rune project: {project_name}");
        println!("Created structure in crates/{target_crate}/");

        Ok(())
    }

    fn find_sources(&self) -> Result<Vec<PathBuf>> {
        let src_dir = self.options.workspace
            .join("crates")
            .join(&self.config.build.target_crate)
            .join("src");

        parser::scan_directory(&src_dir)
    }

    fn parse_sources(sources: &[PathBuf]) -> Result<Vec<parser::SourceFile>> {
        sources.iter().map(|s| parser::parse_file(s.as_path())).collect()
    }

    fn analyze_sources(sources: &[parser::SourceFile]) -> Result<Vec<analyzer::AnalysisResult>> {
        sources.iter().map(analyzer::analyze).collect()
    }

    fn generate_code(
        &self,
        sources: &[parser::SourceFile],
        analyses: &[analyzer::AnalysisResult],
    ) -> Result<Vec<codegen::GeneratedModule>> {
        sources.iter()
            .zip(analyses.iter())
            .map(|(s, a)| codegen::generate(s, a))
            .collect()
    }

    fn write_generated(&self, modules: &[codegen::GeneratedModule]) -> Result<()> {
        let cache_dir = self.cache.generated_dir();

        for module in modules {
            let rel_path = module.name.replace(".r", "");
            let out_path = cache_dir.join(format!("{rel_path}.rs"));
            std::fs::create_dir_all(out_path.parent().unwrap())?;
            std::fs::write(&out_path, &module.source)?;
        }

        Ok(())
    }

    fn build_crate(&self, release: bool) -> Result<()> {
        let manifest = self.cache.generated_cargo_toml();
        let mut cmd = ProcCommand::new("cargo");
        cmd.arg("build");
        if release {
            cmd.arg("--release");
        }
        cmd.arg("--manifest-path").arg(&manifest);

        if !self.options.verbose {
            cmd.stdout(std::process::Stdio::piped());
            cmd.stderr(std::process::Stdio::piped());
        }

        let output = cmd.output()
            .map_err(|e| crate::RuneError::Cargo(e.to_string()))?;

        if !output.status.success() {
            let stderr = String::from_utf8_lossy(&output.stderr);
            return Err(crate::RuneError::Cargo(stderr.to_string()));
        }

        Ok(())
    }

    #[allow(clippy::unnecessary_wraps)]
    fn setup_hot_reload(&self) -> Result<()> {
        let hot_dir = self.options.workspace.join("target/hot");
        std::fs::create_dir_all(&hot_dir)?;

        let profile = match self.options.mode {
            BuildMode::Dev => "debug",
            BuildMode::Release => "release",
        };

        let target_crate = &self.config.build.target_crate;
        let artifact_name = format!("lib{target_crate}.so");

        let artifact = self.options.workspace
            .join("target")
            .join(profile)
            .join(&artifact_name);

        if artifact.exists() {
            let timestamp = std::time::SystemTime::now()
                .duration_since(std::time::UNIX_EPOCH)
                .unwrap()
                .as_millis();

            let safe_name = target_crate.replace('-', "_");
            let hot_name = format!("{safe_name}_{timestamp}.so");
            let hot_path = hot_dir.join(&hot_name);

            std::fs::copy(&artifact, &hot_path)?;

            let current = hot_dir.join(".current");
            if current.exists() {
                std::fs::remove_file(&current)?;
            }

            #[cfg(unix)]
            std::os::unix::fs::symlink(&hot_path, &current)?;

            #[cfg(windows)]
            std::os::windows::fs::symlink_file(&hot_path, &current)?;

            if self.options.verbose {
                println!("Hot reload ready: {hot_name}");
            }
        }

        Ok(())
    }
}

//! # Rune Configuration
//!
//! Project configuration for the Rune compiler.

use std::path::Path;
use serde::{Deserialize, Serialize};

/// Project metadata.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ProjectConfig {
    /// Project name
    pub name: String,
    /// Entry point
    #[serde(default)]
    pub entry: Option<String>,
}

impl Default for ProjectConfig {
    fn default() -> Self {
        Self {
            name: "rune-project".to_string(),
            entry: None,
        }
    }
}

/// Build configuration.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct BuildConfig {
    /// Target crate for hot reload
    #[serde(default = "default_target_crate")]
    pub target_crate: String,
    /// Host crate binary
    #[serde(default = "default_host_crate")]
    pub host_crate: String,
}

fn default_target_crate() -> String {
    "app".to_string()
}

fn default_host_crate() -> String {
    "host".to_string()
}

impl Default for BuildConfig {
    fn default() -> Self {
        Self {
            target_crate: default_target_crate(),
            host_crate: default_host_crate(),
        }
    }
}

/// Development configuration.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct DevConfig {
    /// Enable hot reload
    #[serde(default)]
    pub hot_reload: bool,
    /// Debounce milliseconds
    #[serde(default = "default_debounce")]
    pub debounce: u64,
}

fn default_debounce() -> u64 {
    100
}

impl Default for DevConfig {
    fn default() -> Self {
        Self {
            hot_reload: true,
            debounce: default_debounce(),
        }
    }
}

/// Release configuration.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ReleaseConfig {
    /// Static binary mode
    #[serde(default)]
    pub static_binary: bool,
    /// Link-time optimization
    #[serde(default)]
    pub lto: bool,
}

impl Default for ReleaseConfig {
    fn default() -> Self {
        Self {
            static_binary: true,
            lto: true,
        }
    }
}

/// Full Rune configuration.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct RuneConfig {
    /// Project settings
    pub project: ProjectConfig,
    /// Build settings
    pub build: BuildConfig,
    /// Development settings
    #[serde(default)]
    pub dev: DevConfig,
    /// Release settings
    #[serde(default)]
    pub release: ReleaseConfig,
}

impl Default for RuneConfig {
    fn default() -> Self {
        Self {
            project: ProjectConfig::default(),
            build: BuildConfig::default(),
            dev: DevConfig::default(),
            release: ReleaseConfig::default(),
        }
    }
}

impl RuneConfig {
    /// Load configuration from a file.
    ///
    /// # Errors
    /// Returns an error if the file cannot be read or parsed.
    pub fn load(path: &Path) -> std::io::Result<Self> {
        let content = std::fs::read_to_string(path)?;
        toml::from_str(&content)
            .map_err(|e| std::io::Error::new(std::io::ErrorKind::InvalidData, e))
    }

    /// Save configuration to a file.
    ///
    /// # Errors
    /// Returns an error if the file cannot be written.
    pub fn save(&self, path: &Path) -> std::io::Result<()> {
        let content = toml::to_string_pretty(self)
            .map_err(|e| std::io::Error::new(std::io::ErrorKind::InvalidData, e))?;
        std::fs::write(path, content)
    }
}

//! # Source File Handling
//!
//! Manages source file parsing.

use std::fs;
use std::path::{Path, PathBuf};
use crate::{ParseError, Result};

/// Kind of source file.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum SourceKind {
    /// Standard TypeScript file (.r.ts)
    TypeScript,
    /// TSX file (.r.tsx)
    Tsx,
}

/// A parsed Rune source file.
#[derive(Debug, Clone)]
pub struct SourceFile {
    /// File path
    pub path: PathBuf,
    /// Kind of source file
    pub kind: SourceKind,
    /// Raw source text
    pub source: String,
    /// Module name for display
    pub name: String,
    /// Whether parsing was successful
    pub valid: bool,
    /// Parse errors if any
    pub errors: Vec<ParseError>,
}

impl SourceFile {
    /// Parse a source file from a path.
    ///
    /// # Errors
    /// Returns an error if the file cannot be read.
    pub fn parse(path: &Path, kind: SourceKind) -> Result<Self> {
        if !path.exists() {
            return Err(ParseError::NotFound(path.display().to_string()).into());
        }

        let source = fs::read_to_string(path)?;

        let name = path
            .file_stem()
            .and_then(std::ffi::OsStr::to_str)
            .unwrap_or("module")
            .to_string();

        let errors = Self::validate_syntax(&source);

        Ok(Self {
            path: path.to_path_buf(),
            kind,
            source,
            name,
            valid: errors.is_empty(),
            errors,
        })
    }

    /// Validate basic syntax.
    fn validate_syntax(source: &str) -> Vec<ParseError> {
        let mut errors = Vec::new();
        let mut depth = SyntaxDepth::default();

        let mut in_string = false;
        let mut string_char = '"';
        let mut line = 1u32;

        let chars: Vec<char> = source.chars().collect();
        let mut i = 0;

        while i < chars.len() {
            let c = chars[i];

            if c == '\n' {
                line += 1;
            }

            // Handle string literals
            if !in_string && (c == '"' || c == '\'') {
                in_string = true;
                string_char = c;
            } else if in_string && c == string_char && !escaped(&chars, i) {
                in_string = false;
            } else if !in_string {
                match c {
                    '{' => depth.brace += 1,
                    '}' => {
                        depth.brace -= 1;
                        if depth.brace < 0 {
                            errors.push(ParseError::Parse(format!(
                                "Unexpected closing brace at line {line}"
                            )));
                            depth.brace = 0;
                        }
                    }
                    '(' => depth.paren += 1,
                    ')' => {
                        depth.paren -= 1;
                        if depth.paren < 0 {
                            errors.push(ParseError::Parse(format!(
                                "Unexpected closing parenthesis at line {line}"
                            )));
                            depth.paren = 0;
                        }
                    }
                    '[' => depth.bracket += 1,
                    ']' => {
                        depth.bracket -= 1;
                        if depth.bracket < 0 {
                            errors.push(ParseError::Parse(format!(
                                "Unexpected closing bracket at line {line}"
                            )));
                            depth.bracket = 0;
                        }
                    }
                    _ => {}
                }
            }

            i += 1;
        }

        if depth.brace != 0 {
            errors.push(ParseError::Parse("Unclosed brace(s) at end of file".into()));
        }
        if depth.paren != 0 {
            errors.push(ParseError::Parse("Unclosed parenthesis(es) at end of file".into()));
        }
        if depth.bracket != 0 {
            errors.push(ParseError::Parse("Unclosed bracket(s) at end of file".into()));
        }

        errors
    }

    /// Get line and column from byte offset.
    #[must_use]
    pub fn location_from_offset(&self, offset: u32) -> (u32, u32) {
        let mut line = 1u32;
        let mut col = 1u32;

        for (pos, c) in self.source.chars().enumerate() {
            if pos as u32 >= offset {
                break;
            }
            if c == '\n' {
                line += 1;
                col = 1;
            } else {
                col += 1;
            }
        }

        (line, col)
    }

    /// Get the module name.
    #[must_use]
    pub fn module_name(&self) -> &str {
        &self.name
    }

    /// Check if this is a TSX file.
    #[must_use]
    pub fn is_tsx(&self) -> bool {
        self.kind == SourceKind::Tsx
    }
}

/// Track nested syntax depth.
#[derive(Default)]
struct SyntaxDepth {
    brace: i32,
    paren: i32,
    bracket: i32,
}

/// Check if a character is escaped.
fn escaped(chars: &[char], pos: usize) -> bool {
    let mut count = 0;
    let mut i = pos;
    while i > 0 {
        i -= 1;
        if chars[i] == '\\' {
            count += 1;
        } else {
            break;
        }
    }
    count % 2 == 1
}

/// Parse diagnostics module.
#[allow(dead_code)]
pub mod diagnostics {
    use crate::ParseError;

    /// Accumulated parse diagnostics.
    #[derive(Debug, Default)]
    pub struct ParseDiagnostics {
        errors: Vec<ParseError>,
    }

    impl ParseDiagnostics {
        /// Create a new diagnostics collector.
        #[must_use]
        pub const fn new() -> Self {
            Self { errors: Vec::new() }
        }

        /// Add an error.
        pub fn add_error(&mut self, err: ParseError) {
            self.errors.push(err);
        }

        /// Check if there are any errors.
        #[must_use]
        pub const fn has_errors(&self) -> bool {
            !self.errors.is_empty()
        }

        /// Get all errors.
        #[must_use]
        pub fn errors(&self) -> &[ParseError] {
            &self.errors
        }

        /// Take all errors, leaving an empty collector.
        pub fn take_errors(&mut self) -> Vec<ParseError> {
            std::mem::take(&mut self.errors)
        }
    }

    impl std::fmt::Display for ParseDiagnostics {
        fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
            write!(f, "Parse errors: {}", self.errors.len())
        }
    }
}

//! # Core Emitter
//!
//! Main RustEmitter implementation.

use crate::{parser::SourceFile, analyzer::AnalysisResult};
use crate::codegen::{GeneratedModule, CodegenOptions};

/// Options for code emission.
#[derive(Debug, Clone, Default)]
pub struct EmitOptions {
    /// Generate debug info
    pub source_map: bool,
    /// Pretty print output
    pub pretty: bool,
}

/// Emits Rust code from TypeScript source.
#[derive(Debug)]
pub struct RustEmitter<'a> {
    /// Source file being transpiled
    pub(crate) source: &'a SourceFile,
    /// Analysis results
    pub(crate) analysis: &'a AnalysisResult,
    /// Imports needed by this module
    pub(crate) imports: Vec<crate::codegen::Import>,
    /// Output buffer
    pub(crate) output: String,
    /// Current indentation level
    pub(crate) indent: usize,
    /// Generation options
    #[allow(unused)]
    options: CodegenOptions,
}

impl<'a> RustEmitter<'a> {
    /// Create a new emitter.
    #[must_use]
    pub fn new(source: &'a SourceFile, analysis: &'a AnalysisResult) -> Self {
        Self {
            source,
            analysis,
            imports: Vec::new(),
            output: String::new(),
            indent: 0,
            options: CodegenOptions::default(),
        }
    }

    /// Emit the complete module.
    ///
    /// # Errors
    /// Returns an error if code generation fails.
    pub fn emit(mut self) -> crate::Result<GeneratedModule> {
        use super::module;
        self.write_header();
        module::write_types(&mut self);
        module::write_functions(&mut self);
        self.write_footer();

        let name = self.source.path.file_stem()
            .and_then(std::ffi::OsStr::to_str)
            .unwrap_or("module")
            .to_string();

        Ok(GeneratedModule {
            name,
            source: self.output,
            imports: self.imports,
            types: Vec::new(),
            functions: Vec::new(),
        })
    }

    /// Write module header with imports.
    fn write_header(&mut self) {
        use super::module;
        module::write_header(self);
    }

    /// Write type definitions.
    fn write_types(&mut self) {
        use super::module;
        module::write_types(self);
    }

    /// Write function definitions.
    fn write_functions(&mut self) {
        use super::module;
        module::write_functions(self);
    }

    /// Write module footer.
    fn write_footer(&mut self) {
        self.push_line("// End of generated code");
    }

    /// Emit a single function definition.
    fn emit_function(&mut self, name: &str, func: &crate::analyzer::FunctionInfo) {
        use super::module;
        module::emit_function(self, name, func);
    }

    /// Generate function body from source.
    fn generate_function_body(&mut self, name: &str) {
        use super::stmt::StmtTranspiler;
        StmtTranspiler::generate_function_body(self, name);
    }

    /// Translate a TypeScript line to Rust.
    fn translate_line(&mut self, line: &str) {
        use super::stmt::StmtTranspiler;
        StmtTranspiler::translate_line(self, line);
    }

    /// Translate an expression.
    fn translate_expr(&self, expr: &str) -> String {
        use super::expr::ExprTranspiler;
        ExprTranspiler::new(self).transpile(expr)
    }

    /// Translate a condition.
    fn translate_condition(&self, cond: &str) -> String {
        use super::expr::ExprTranspiler;
        ExprTranspiler::new(self).transpile_condition(cond)
    }

    pub(crate) fn push_line(&mut self, s: &str) {
        self.output.push_str(s);
        self.output.push('\n');
    }

    pub(crate) fn push_indent(&mut self) {
        for _ in 0..self.indent {
            self.output.push_str("    ");
        }
    }
}

