use crate::protocol::{AppState, Filter, Task};
use ratatui::{
    widgets::{Block, Borders, List, ListItem, Paragraph},
    style::{Style, Color},
    widgets::Widget,
};

/// Task list component.
pub fn render(state: &AppState) -> impl Widget {
    let visible_tasks: Vec<&Task> = match state.filter {
        Filter::Active => state.tasks.iter().filter(|t| !t.done).collect(),
        Filter::Completed => state.tasks.iter().filter(|t| t.done).collect(),
        Filter::All => state.tasks.iter().collect(),
    };

    let items: Vec<ListItem> = visible_tasks.iter().enumerate().map(|(i, task)| {
        let checkbox = if task.done { "[x]" } else { "[ ]" };
        let content = format!("{} {}", checkbox, task.title);
        let is_selected = i == state.selected;
        let style = if is_selected {
            Style::new().add_modifier(ratatui::style::Modifier::REVERSED)
        } else if task.done {
            Style::new().fg(Color::DarkGray)
        } else {
            Style::default()
        };
        ListItem::new(content).style(style)
    }).collect();

    let list = List::new(items)
        .block(Block::default()
            .title(format!("Tasks ({})", visible_tasks.len()))
            .borders(Borders::ALL))
        .highlight_style(Style::new().bg(Color::Blue));

    if visible_tasks.is_empty() {
        let empty = Paragraph::new("No tasks. Press 'a' to add one.")
            .block(Block::default().borders(Borders::ALL));
        empty
    } else {
        list
    }
}

//! # App Library
//!
//! Hot-reloadable application logic.
//! This file is auto-generated - edit main.r.ts instead.

mod native;
mod generated;

// Re-export generated modules
pub use generated::*;

/// Create the app instance.
#[no_mangle]
pub extern "C" fn create_app() -> *mut dyn protocol::App {
    Box::into_raw(Box::new(AppImpl::default()))
}

/// App implementation.
#[derive(Default)]
struct AppImpl;

impl protocol::App for AppImpl {
    fn update(&mut self, state: &mut protocol::AppState) {
        generated::main::update(state);
    }

    fn render(&self, f: &mut ratatui::Frame<'_>, state: &protocol::AppState) {
        let widget = generated::views::root::render(state);
        f.render_widget(widget, f.size());
    }

    fn handle_key(
        &mut self,
        key: crossterm::event::KeyEvent,
        state: &mut protocol::AppState,
    ) {
        use crossterm::event::KeyCode;
        match key.code {
            KeyCode::Up | KeyCode::Char('k') => {
                if state.selected > 0 {
                    state.selected -= 1;
                }
            }
            KeyCode::Down | KeyCode::Char('j') => {
                if state.selected < state.tasks.len().saturating_sub(1) {
                    state.selected += 1;
                }
            }
            KeyCode::Enter | KeyCode::Char(' ') => {
                if let Some(task) = state.tasks.get_mut(state.selected) {
                    task.done = !task.done;
                }
            }
            KeyCode::Char('a') => {
                state.tasks.push(protocol::Task {
                    id: rand_id(),
                    title: "New Task".to_string(),
                    done: false,
                });
            }
            KeyCode::Char('d') => {
                state.tasks.remove(state.selected);
                state.selected = state.selected.saturating_sub(1);
            }
            KeyCode::Char('f') => {
                state.filter = match state.filter {
                    protocol::Filter::All => protocol::Filter::Active,
                    protocol::Filter::Active => protocol::Filter::Completed,
                    protocol::Filter::Completed => protocol::Filter::All,
                };
            }
            KeyCode::Char('q') | KeyCode::Esc => {
                state.should_exit = true;
            }
            _ => {}
        }
    }
}

/// Generate a random ID.
fn rand_id() -> i32 {
    use std::time::{SystemTime, UNIX_EPOCH};
    SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap()
        .as_millis() as i32
}

